&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;चेन्नई तमिलनाडु राज्य की राजधानी&lt;/strong&gt; है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;डेट्रॉइट मिशिगन का एक शहर &lt;/strong&gt;है जिसे &lt;strong&gt;आधुनिक ऑटोमोबाइल के जनक स्थल&lt;/strong&gt;&amp;nbsp;के रूप में जाना जाता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;चेन्नई&lt;/strong&gt; को&lt;strong&gt; पहले मद्रास कहा जाता था।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;1996&lt;/strong&gt; में &lt;strong&gt;मद्रास, चेन्नई &lt;/strong&gt;बन गया।&lt;/li&gt;
	&lt;li&gt;शहर के चारों ओर &lt;strong&gt;प्रमुख ऑटोमोबाइल विनिर्माण इकाइयों&lt;/strong&gt; और अन्य उद्योगों की उपस्थिति के कारण &lt;strong&gt;चेन्नई&lt;/strong&gt; को &lt;strong&gt;&amp;quot;एशिया का डेट्रॉइट&amp;quot; &lt;/strong&gt;उपनाम दिया गया है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;भारत का एक तिहाई से अधिक ऑटोमोबाइल उद्योग चेन्नई में स्थित है।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;चेन्नई भारत का सबसे पुराना नगर निगम है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;भारतीय समुद्री विश्वविद्यालय चेन्नई में स्थित है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;भारत का पहला साइबर डाकघर चेन्नई में स्थापित किया गया था।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;भारत का पहला कृषि बैंक चेन्नई में स्थापित किया गया था।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;दक्षिणी रेलवे का मुख्यालय चेन्नई में है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;प्रसिद्ध मरीना बीच चेन्नई में है।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

