&lt;/table&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;कोलकाता&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: 33, 37, 41);&quot;&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;कोल इंडिया लिमिटेड (CIL)&lt;/strong&gt;&lt;/u&gt; का &lt;u&gt;&lt;strong&gt;मुख्यालय कोलकाता&lt;/strong&gt;&lt;/u&gt; में स्थित है।&lt;/li&gt;
	&lt;li&gt;कोल इंडिया लिमिटेड एक&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;महारत्न स्थिति कंपनी&lt;/span&gt;&amp;nbsp;है और दुनिया की सबसे बड़ी कोयला उत्पादक कंपनी है। &amp;nbsp;&lt;/li&gt;
	&lt;li&gt;इसकी &lt;strong&gt;स्थापना 1975 &lt;/strong&gt;में कोयला उद्योग के राष्ट्रीयकरण के बाद 1975 में हुई थी। &amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;color: 33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: (33, 37, 41);&quot;&gt;
