		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;&lt;span style=&quot;&quot;&gt;Natya Shastra&lt;/span&gt;&lt;/td&gt;
			&lt;td&gt;Bharata Muni&lt;/td&gt;
		&lt;/tr&gt;
