			&lt;td&gt;&lt;span style=&quot;&quot;&gt;Romaka Siddhanta&lt;/span&gt;&lt;/td&gt;
			&lt;td&gt;Varahamihira&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;<br><br>&lt;p&gt;सही उत्तर &lt;span style=&quot;font-weight: bolder;&quot;&gt;आर्यभटीय&amp;nbsp;&lt;/span&gt;है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;आर्यभटीय&lt;/span&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;आर्यभटीय&amp;nbsp;&lt;/span&gt;&lt;strong&gt;आर्यभट द्वारा लिखी गयी&amp;nbsp;थी।&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;पाँचवीं शताब्दी&amp;nbsp;&lt;/span&gt;के&amp;nbsp;&lt;strong&gt;भारतीय गणितज्ञ आर्यभट्ट&lt;/strong&gt;&amp;nbsp;का एकमात्र ज्ञात जीवित कार्य &lt;strong&gt;संस्कृत खगोलीय ग्रंथ&lt;/strong&gt; है जिसे&lt;strong&gt; आर्यभटीय&amp;nbsp;&lt;/strong&gt;के नाम से जाना जाता है।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;रोजर बिलार्ड,&lt;/strong&gt; एक खगोल विज्ञान &lt;strong&gt;दार्शनिक,&lt;/strong&gt;&amp;nbsp;की परिकल्पना है कि पुस्तक 510 ईसा के आसपास ऐतिहासिक संदर्भों के आधार पर लिखी गई थी।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;आर्यभटीय में &lt;/strong&gt;चार &lt;strong&gt;अध्याय या भाग&lt;/strong&gt; हैं। &lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;प्रारंभिक भाग&amp;nbsp;&lt;/span&gt;दशगीतिकापाद&lt;strong&gt;&amp;nbsp;13 श्लोकों&lt;/strong&gt; से बना है।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;&amp;quot;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;दशगीतिकापाद&lt;/span&gt;&amp;quot;&lt;/strong&gt; या&lt;strong&gt; &amp;quot;दस छंद,&amp;quot; आर्यभटीय &lt;/strong&gt;का परिचय, पुस्तक का पहला खंड है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;पुस्तकें और लेखक&lt;/li&gt;
&lt;/ul&gt;

